// Récupération des données globales
let enrichedVars = global.get("enrichedVars") || {}; 
let tableauPourUI = [];

// On réinitialise la sélection à chaque rafraîchissement de liste
flow.set("varSelected", ""); 

// Parcours de toutes les variables du fichier globalSave
Object.entries(enrichedVars).forEach(([nomVarG, e]) => {
    if (!nomVarG || !e || typeof e !== "object") return;

    // On prépare un résumé des propriétés pour l'affichage tableau
    let props = e.proprietes || [];
    let proprieteResume = props.length > 0 ? props.map(p => p.nomP).join(", ") : "";

    // On pousse l'objet complet vers le tableau UI
    tableauPourUI.push({
        nomVarG: nomVarG,
        instances: (e.instances || ["*"]).join(", "),
        proprietes: proprieteResume,
        descriptionVarG: e.descriptionVarG || "", // On garde le champ description
        dateUpdateVarG: e.dateUpdateVarG || ""    // On garde la date
    });
});

msg.payload = tableauPourUI;
return msg;

// =================================================================
// 🔹 InfosSauvegardeVars
// - Enregistre les modifs de la variable globale
// - Gère le renommage de la clé dans l'objet global
// =================================================================

const nodeFs = global.get('nodeFs');
const filePath = '/data/data/com.termux/files/home/.node-red/globalSave.json';

let enrichedVars = global.get("enrichedVars") || {};
let varSelected = flow.get("varSelected");
let formData = msg.payload;

if (!formData || !formData.nomVarG) return null;

let newName = formData.nomVarG.trim();
let oldName = (varSelected === "new") ? null : varSelected;

if (!oldName || !enrichedVars[oldName]) {
    // CRÉATION : Nouvel objet
    enrichedVars[newName] = {
        nomVarG: newName,
        nomCpletVarG: formData.nomCpletVarG || "",
        instances: formData.instances ? formData.instances.split(",").map(e => e.trim()) : ["*"],
        descriptionVarG: formData.descriptionVarG || "",
        dateUpdateVarG: new Date().toISOString(),
        proprietes: []
    };
} else {
    // MODIFICATION : On récupère l'existant pour ne rien écraser (les P notamment)
    let data = enrichedVars[oldName];

    if (oldName !== newName) {
        enrichedVars[newName] = data; // On déplace les données
        delete enrichedVars[oldName]; // On supprime l'ancienne clé
    }

    // Mise à jour des champs modifiables
    enrichedVars[newName].nomVarG = newName;
    enrichedVars[newName].nomCpletVarG = formData.nomCpletVarG;
    enrichedVars[newName].instances = formData.instances.split(",").map(e => e.trim());
    enrichedVars[newName].descriptionVarG = formData.descriptionVarG;
    enrichedVars[newName].dateUpdateVarG = new Date().toISOString();
}

// Persistence
global.set("enrichedVars", enrichedVars);
try {
    const toSave = { enrichedVars: enrichedVars, lastUpdate: new Date().toISOString() };
    nodeFs.writeFileSync(filePath, JSON.stringify(toSave, null, 4), 'utf8');
} catch (err) { node.error(err); }

flow.set("varSelected", newName);
msg.payload = newName;
return msg;

// 🔹 recupVarSelected
// - Détermine si on sélectionne une variable existante ou si on crée une nouvelle
// - Met à jour flow.varSelected
// - Fournit msg.info et msg.payload adaptés

let enrichedVars = global.get("enrichedVars") || {};
let listeVars = Object.keys(enrichedVars);
let varSelected = null;

// 1) Cas bouton "Ajouter une VarG"
if (msg.topic === "newVarG") {
    varSelected = "new";
}
// 2) Cas sélection dans la table
else {
    varSelected = msg.payload?.row?.nomVarG || msg.payload?.nomVarG || null;
}

// 3) Vérification : aucune sélection
if (!varSelected) {
    msg.info = (listeVars.length === 0)
        ? "⚠️ Aucune variable existante dans enrichedVars."
        : "⚠️ Aucune variable sélectionnée pour édition.";
    return msg;  // on sort proprement
}

// 4) Stockage de la sélection
flow.set("varSelected", varSelected);

// 5) Message d'info
msg.info = (varSelected === "new")
    ? "➕ Création d'une nouvelle variable."
    : `✅ Vous êtes sur la variable : ${varSelected}`;

// 6) Retour
msg.payload = varSelected;
return msg;

// =================================================================
// 🔹 prepareFormVarSelected
// - Prépare le formulaire Form_Var_Modif selon varSelected
// - Gère : création nouvelle variable, édition variable existante
// =================================================================

let enrichedVars = global.get("enrichedVars") || {};
let varSelected = flow.get("varSelected") || null;

// 1) Cas création d'une nouvelle variable
if (varSelected === "new") {
    msg.payload = {
        nomVarG: "",
        nomCpletVarG: "", // Gardé pour compatibilité
        instances: "*", 
        descriptionVarG: "- Objectif(s): \n- Origine: \n- Autres : ",
        dateUpdateVarG: new Date().toISOString()
    };
    msg.topic = "newVarG";
    return msg;
}

// 2) Cas édition d'une variable existante
if (varSelected && enrichedVars[varSelected]) {
    const selected = enrichedVars[varSelected];
    msg.payload = {
        nomVarG: selected.nomVarG || varSelected,
        nomCpletVarG: selected.nomCpletVarG || "", // On ne supprime rien
        instances: selected.instances ? selected.instances.join(", ") : "*",
        descriptionVarG: selected.descriptionVarG || "",
        dateUpdateVarG: selected.dateUpdateVarG || new Date().toISOString()
    };
    return msg;
}

// 3) Cas par défaut / Sécurité
msg.payload = {
    nomVarG: "",
    nomCpletVarG: "",
    instances: "",
    descriptionVarG: "",
    dateUpdateVarG: new Date().toISOString()
};
return msg;

const nodeFs = global.get('nodeFs');
const filePath = '/data/data/com.termux/files/home/.node-red/globalSave.json';

if (msg.payload === "confirm_clicked") {
    const varToDelete = flow.get("pendingDeletion");
    let enrichedVars = global.get("enrichedVars") || {};

    if (varToDelete && enrichedVars[varToDelete]) {
        // 1. Suppression RAM
        delete enrichedVars[varToDelete];
        global.set("enrichedVars", enrichedVars);

        // 2. Persistance Disque immédiate
        try {
            if (Object.keys(enrichedVars).length === 0) {
                // Optionnel : protéger si on veut interdire de supprimer la DERNIÈRE variable
                // ou simplement autoriser un fichier vide :
                nodeFs.writeFileSync(filePath, JSON.stringify({ enrichedVars: {}, lastUpdate: new Date().toISOString() }, null, 4));
            } else {
                nodeFs.writeFileSync(filePath, JSON.stringify({ enrichedVars: enrichedVars, lastUpdate: new Date().toISOString() }, null, 4));
            }
            node.warn(`🗑️ Variable ${varToDelete} supprimée (RAM & Disque)`);
        } catch (err) {
            node.error("❌ Erreur lors de la suppression disque : " + err.message);
        }
    }

    flow.set("varSelected", null);
    msg.payload = "refresh";
    return msg;
}
return null;

// open-dialog -> Preparation d'une Boite de Dialogue Suppression
// les actions dans ui-notification doivent être configuré selon un schéma précis
const varSelected = flow.get("varSelected") || null;

if (!varSelected || varSelected === "none" || varSelected === "new") {
    msg.payload = {
        type: "warning", 
        title: "Aucune variable",
        text: "Veuillez sélectionner une variable à supprimer.",
        duration: 3000
    };
    return msg;
}

flow.set("pendingDeletion", varSelected);
// gestion dynamique du ui-notification, les mots clefs de ui-update sont spécifique au noeud
msg.payload = {
    type: "warning",
    title: "Confirmation suppression",
    text: `Voulez-vous vraiment supprimer la variable "<strong>${varSelected}</strong>" ?`,
    displayTime: 0, // Ne pas fermer automatiquement
    ui_update: {
        allowConfirm: true,
        allowDismiss: true,
        confirmText: "✅ Supprimer",
        dismissText: "❌ Annuler"
    }
};

return msg;

/*******************************************************************************
 * NOM DU NŒUD : chargeEnrichedVarsToMemory
 * RÔLE : Charger le dictionnaire maître en RAM au lancement de l'UI
 * DERNIÈRE MODIF : 24/03/2026 - Cohérence SF_Init_1 / nodeFs
 ******************************************************************************/

// --- CONFIGURATION ---
const nodeFs = global.get('nodeFs');
const filePath = '/data/data/com.termux/files/home/.node-red/globalSave.json';

// --- FONCTIONS DE COHÉRENCE (Identiques à SF_Init_1) ---
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        default: return "";
    }
}

// 1. TENTATIVE DE RÉCUPÉRATION RAM
let enrichedVars = global.get("enrichedVars");

// 2. SI RAM VIDE : LECTURE PHYSIQUE DU FICHIER (nodeFs)
if (!enrichedVars || Object.keys(enrichedVars).length === 0) {
    try {
        if (nodeFs.existsSync(filePath)) {
            const rawData = nodeFs.readFileSync(filePath, 'utf8');
            const parsed = JSON.parse(rawData);
            enrichedVars = parsed.enrichedVars || {};

            // On peuple la RAM pour que le reste de l'UI fonctionne immédiatement
            global.set("enrichedVars", enrichedVars);
            node.status({ fill: "blue", shape: "dot", text: "Chargé depuis Disque" });
        } else {
            node.error("🚨 CRITIQUE : globalSave.json introuvable !");
            node.status({ fill: "red", shape: "ring", text: "Fichier absent" });
            return null;
        }
    } catch (e) {
        node.error("🚨 Erreur de lecture : " + e.message);
        return null;
    }
} else {
    node.status({ fill: "green", shape: "dot", text: "Données RAM prêtes" });
}

// 3. TRANSFERT VERS LE FLOW UI
msg.payload = enrichedVars;
return msg;

