// =================================================================
// 🔹 routerAction (SÉCURISÉ ANTI-BOUCLE)
// =================================================================

// 1. ANTI-BOUCLE : Si c'est un message de retour (refresh/save), on stoppe net.
if (msg.topic === "refresh" || msg.topic === "saveBase" || msg.topic === "saveValues") {
    return null;
}

// 2. Extraction des données (cherche à la racine OU dans payload)
let action = msg.action || (msg.payload ? msg.payload.action : null);
let prop = msg.prop || (msg.payload ? msg.payload.prop : null);

// Si aucune intention d'action n'est trouvée, on ne fait rien
if (!action || !prop) return null;

// 3. Mémoire pour le nom original (utile pour SauvResultatActions)
flow.set("propOriginalName", (prop.nomP === 'NouvelleP') ? null : prop.nomP);

// 4. Routage vers les 3 sorties
// --- SORTIE 1 : Base ---
if (action === "base") {
    msg.topic = "openEditor";
    msg.editor = "base";
    msg.prop = (prop._isNew) ? { nomP: "", nomCpletP: "", descriptionP: "", typeP: "string", optionsP: [] } : prop;
    return [msg, null, null];
}

// --- SORTIE 2 : Valeurs ---
if (action === "valeurs") {
    msg.topic = "openEditor"; // FIX BUG 2 : Réveille le v-if du template
    msg.editor = "valeurs";   // FIX BUG 2
    msg.prop = prop;
    msg.instances = flow.get("instances") || ["*"];
    return [null, msg, null];
}

// --- SORTIE 3 : Delete ---
if (action === "delete") {
    msg.topic = "delete";
    msg.prop = prop;
    return [null, null, msg];
}

return null;

// =================================================================
// 🔹 prepareTableauProprietes
// - Prépare l'objet complexe pour le Template_Proprietes
// - REQUIS : msg.payload.instances, .proprietes, .variable
// =================================================================

let varSelected = flow.get("varSelected");
let enrichedVars = global.get("enrichedVars") || {};

// Si aucune sélection, on envoie une structure vide pour éviter les erreurs Vue
if (!varSelected || !enrichedVars[varSelected]) {
    msg.payload = { proprietes: [], instances: ["*"], variable: { nomVarG: "Sélectionnez une VarG" } };
    return msg;
}

let variable = enrichedVars[varSelected];

// --- FIX : PARSING DES INSTANCES ---
let instList = variable.instances || ["*"];

// Si c'est un tableau de 1 élément qui contient des ";", on le découpe
if (Array.isArray(instList) && instList.length === 1 && instList[0].includes(';')) {
    instList = instList[0].split(';').map(s => s.trim()).filter(s => s !== "");
}
// Si jamais c'était resté une simple String
else if (typeof instList === 'string') {
    instList = instList.split(';').map(s => s.trim()).filter(s => s !== "");
}

// On s'assure que "*" est toujours là et en premier
if (!instList.includes("*")) instList.unshift("*");
// -----------------------------------

// 1. On prépare la liste des lignes (P)
let listeP = (variable.proprietes || []).map(p => {
    return {
        nomP: p.nomP,
        nomCpletP: p.nomCpletP || "",
        descriptionP: p.descriptionP || "",
        typeP: p.typeP || "string",
        valeurs: p.valeurs || {},
        defaut: (p.valeurs && p.valeurs["*"]) !== undefined ? p.valeurs["*"] : "-"
    };
});

// 2. Ajout ligne "NouvelleP"
listeP.push({ nomP: 'NouvelleP', _isNew: true, typeP: 'string' });

// 3. Stockage des instances PROPRES dans le flow
flow.set("instances", instList);

// 4. On construit le payload pour le Template HTML
msg.payload = {
    proprietes: listeP,
    instances: instList, // Ici on envoie le tableau découpé
    variable: { nomVarG: variable.nomVarG }
};

return msg;

// =================================================================
// 🔹 SauvResultatActions (CODE COMPLET)
// =================================================================

const nodeFs = global.get('nodeFs');
const filePath = '/data/data/com.termux/files/home/.node-red/globalSave.json';

let enriched = global.get('enrichedVars') || {};
let varSelected = flow.get('varSelected');
let originalName = flow.get("propOriginalName");

if (!varSelected || !enriched[varSelected]) return null;
let variable = enriched[varSelected];

// --- CAS A : Sauvegarde Structure (Base) ---
if (msg.topic === "saveBase") {
    let p = msg.payload;

    // 1. Mise à jour des instances si présentes (Parsing par virgule ou ;)
    if (msg.instancesInput) {
        let newInst = msg.instancesInput.split(/[ ,;]+/).map(s => s.trim()).filter(s => s !== "");
        if (!newInst.includes("*")) newInst.unshift("*");
        variable.instances = newInst;
    }

    let idx = variable.proprietes.findIndex(pr => pr.nomP === originalName);

    // On conserve les valeurs existantes même si on change la structure
    let oldProp = (idx >= 0) ? variable.proprietes[idx] : { valeurs: {} };

    let updatedProp = {
        nomP: p.nomP,
        nomCpletP: p.nomCpletP || "",
        descriptionP: p.descriptionP || "",
        typeP: "string", // Comme convenu, le type affiché est string
        optionsP: Array.isArray(p.optionsP) ? JSON.parse(JSON.stringify(p.optionsP)) : [],
        valeurs: oldProp.valeurs || { "*": "" }
    };

    // Initialisation des clés manquantes pour les nouvelles instances
    (variable.instances || ["*"]).forEach(i => {
        if (updatedProp.valeurs[i] === undefined) updatedProp.valeurs[i] = "";
    });

    if (idx === -1) {
        variable.proprietes.push(updatedProp);
    } else {
        variable.proprietes[idx] = updatedProp;
    }
}

// --- CAS B : Sauvegarde Valeurs ---
else if (msg.topic === "saveValues") {
    if (msg.prop && msg.prop.nomP) {
        let idx = variable.proprietes.findIndex(pr => pr.nomP === msg.prop.nomP);
        if (idx >= 0) {
            // On écrase le dictionnaire de valeurs avec celui venant de l'éditeur
            variable.proprietes[idx].valeurs = JSON.parse(JSON.stringify(msg.prop.valeurs));
        }
    }
}

// --- CAS C : Suppression ---
else if (msg.topic === "delete") {
    if (msg.prop && msg.prop.nomP) {
        variable.proprietes = variable.proprietes.filter(p => p.nomP !== msg.prop.nomP);
    }
}

// --- PERSISTANCE ---
global.set('enrichedVars', enriched);
try {
    nodeFs.writeFileSync(filePath, JSON.stringify({
        enrichedVars: enriched,
        lastUpdate: new Date().toISOString()
    }, null, 4), 'utf8');
} catch (err) {
    node.error("Erreur écriture JSON: " + err);
}

// --- SORTIE REFRESH ---
return {
    topic: "refresh",
    payload: true
};

// Noeud "Gestion Sélection Automatique" - VERSION CORRIGÉE
let varSelected = msg.payload;

console.log("Gestion Sélection Automatique - varSelected:", varSelected);

if (varSelected && varSelected !== "new") {
    // Variable existante sélectionnée
    flow.set('varSelected', varSelected);
    console.log("Variable sélectionnée automatiquement:", varSelected);

    // Préparer les messages pour les deux composants
    let formMsg = {
        topic: "refresh",
        payload: varSelected,
        info: `✅ Vous êtes sur la variable : ${varSelected}`
    };

    let tableauMsg = {
        topic: 'refresh',
        view: 'tableau',
        payload: varSelected
    };

    return [formMsg, tableauMsg];

} else if (varSelected === "new") {
    // Nouvelle variable
    flow.set('varSelected', "new");

    // Préparer les messages pour les deux composants
    let formMsg = {
        topic: "newVarG",
        info: "➕ Création d'une nouvelle variable.",
        payload: {
            nomVarG: "",
            nomCpletVarG: "",
            instances: "*",
            descriptionVarG: "- Objectif(s): - Origine: - Autres : ",
            dateUpdateVarG: new Date().toISOString()
        }
    };

    let tableauMsg = {
        topic: 'refresh',
        view: 'tableau',
        payload: "new"
    };

    return [formMsg, tableauMsg];

} else {
    // Aucune sélection
    return [null, null];
}

// Noeud "Initialisation Page"
// S'exécute au chargement de la page pour reset l'état

// Reset les sélections au chargement
flow.set('varSelected', null);
flow.set('propSelected', null);
flow.set('infoAction', "Sélectionnez une variable");

// Préparer un tableau vide
msg.payload = {
    proprietes: [{
        nomP: 'NouvelleP',
        nomCpletP: 'New',
        typeP: null,
        schema: null,
        valeurs: { '*': null },
        _isNew: true
    }],
    propSelected: null,
    instances: [],
    variable: { nomVarG: "Aucune variable sélectionnée" }
};
msg.info = "Sélectionnez une variable dans le tableau";

return msg;

// Voir ce qui existe dans le stockage fichier
let fileData = global.get("enrichedVars", "file");
node.warn("Données dans le fichier: " + JSON.stringify(fileData));

// Voir tous les keys disponibles (si supporté)
try {
    let keys = global.keys("file");
    node.warn("Clés disponibles dans le fichier: " + JSON.stringify(keys));
} catch(e) {
    node.warn("keys() non supporté: " + e.message);
}

/* Le nœud ui-notification envoie un message avec msg.payload contenant :
   - "confirm_clicked" si l'utilisateur clique sur "✅ Supprimer".
   - "dismiss_clicked" si l'utilisateur clique sur "❌ Annuler".
*/
if (msg.payload === "confirm_clicked") {
    const varToDelete = flow.get("pendingDeletion");

    if (!varToDelete) {
        msg.info = "⚠️ Aucune variable en attente de suppression.";
        return msg;
    }

    // Suppression
    let enrichedVars = global.get("enrichedVars", "file") || {};
    delete enrichedVars[varToDelete];
    delete enrichedVars[""];
    global.set("enrichedVars", enrichedVars, "file");
    global.set(varToDelete, undefined, "default");
    flow.set("varSelected", "none");
    flow.set("pendingDeletion", null);

    msg.payload = "none";
    msg.info = `✅ Variable "${varToDelete}" supprimée.`;
    msg.notification = {
        type: "success",
        title: "✅ Supprimée",
        text: `Variable "${varToDelete}" supprimée avec succès.`,
        duration: 3000
    };

} else if (msg.payload === "dismiss_clicked") {
    flow.set("pendingDeletion", null);
    msg.info = "❌ Suppression annulée.";
    msg.notification = {
        type: "info",
        title: "❌ Annulée",
        text: "Suppression annulée.",
        duration: 3000
    };
}

return msg;

// Dans le noeud "routerAction" - version corrigée
let action = msg.action;
let prop = msg.prop || {};
let varSelected = flow.get('varSelected');
let enriched = global.get('enrichedVars', 'file') || {};
let variable = enriched[varSelected] || {};
let instances = (variable.instances || []).filter(i => i !== '*');

if (action) flow.set('propSelected', prop && prop.nomP ? prop.nomP : null);

// CORRECTION : Récupérer la propriété COMPLÈTE depuis la variable
let completeProp = prop;
if (prop.nomP && !prop._isNew) {
    // Chercher la propriété complète dans la variable
    let foundProp = (variable.proprietes || []).find(p => p.nomP === prop.nomP);
    if (foundProp) {
        completeProp = foundProp;
    }
}

// Gestion de l'éditeur Base (nouveau ou modification)
if (action === 'base') {
    // Si c'est une nouvelle propriété (_isNew = true), on envoie un objet vide
    // Sinon, on envoie la propriété complète
    let propData = prop._isNew ? {} : completeProp;

    return [{
        topic: 'openEditor',
        editor: 'base',
        prop: propData,
        instances: instances,
        originalName: prop._isNew ? null : prop.nomP
    }, null, null];
}
// Gestion de l'éditeur Valeurs
else if (action === 'valeurs') {
    return [null, {
        topic: 'openEditor',
        editor: 'valeurs',
        prop: completeProp,  // ← Propriété COMPLÈTE avec useValueList et valueList
        instances: instances,
        originalName: prop.nomP
    }, null];
}
else if (action === 'delete') { 
    return [null, null, { topic: 'delete', prop }]; 
}
return null;

// =================================================================
// 🔹 SauvResultatActions (VERSION CORRIGÉE)
// =================================================================

const nodeFs = global.get('nodeFs');
const filePath = '/data/data/com.termux/files/home/.node-red/globalSave.json';

let enriched = global.get('enrichedVars') || {};
let varSelected = flow.get('varSelected');
let originalName = flow.get("propOriginalName");

if (!varSelected || !enriched[varSelected]) return null;
let variable = enriched[varSelected];

// --- CAS A : Sauvegarde Structure (Base) ---
if (msg.topic === "saveBase") {
    let p = msg.payload;

    // 1. Mise à jour des instances (Parsing par virgule)
    if (msg.instancesInput) {
        let newInst = msg.instancesInput.split(',').map(s => s.trim()).filter(s => s !== "");
        if (!newInst.includes("*")) newInst.unshift("*");
        variable.instances = newInst;
    }

    let idx = variable.proprietes.findIndex(pr => pr.nomP === originalName);

    // On récupère l'ancienne version pour ne pas perdre les valeurs
    let oldProp = (idx >= 0) ? variable.proprietes[idx] : { valeurs: {} };

    let updatedProp = {
        nomP: p.nomP,
        nomCpletP: p.nomCpletP || "",
        descriptionP: p.descriptionP || "",
        typeP: "string", // On force string car optionsP définit l'enum
        optionsP: Array.isArray(p.optionsP) ? p.optionsP : [],
        valeurs: oldProp.valeurs || { "*": "" }
    };

    if (idx === -1) {
        // Initialisation des valeurs manquantes pour les instances
        (variable.instances || ["*"]).forEach(i => {
            if (updatedProp.valeurs[i] === undefined) updatedProp.valeurs[i] = "";
        });
        variable.proprietes.push(updatedProp);
    } else {
        variable.proprietes[idx] = updatedProp;
    }
}

// --- CAS B : Sauvegarde Valeurs ---
else if (msg.topic === "saveValues") {
    if (msg.prop && msg.prop.nomP) {
        let idx = variable.proprietes.findIndex(pr => pr.nomP === msg.prop.nomP);
        if (idx >= 0) {
            // On sauvegarde l'objet valeurs complet (incluant la propagation faite par l'UI)
            variable.proprietes[idx].valeurs = JSON.parse(JSON.stringify(msg.prop.valeurs));
        }
    }
}

// --- CAS C : Suppression ---
else if (msg.topic === "delete") {
    variable.proprietes = variable.proprietes.filter(p => p.nomP !== msg.prop.nomP);
}

// --- PERSISTANCE ---
global.set('enrichedVars', enriched);
try {
    nodeFs.writeFileSync(filePath, JSON.stringify({ enrichedVars: enriched, lastUpdate: new Date().toISOString() }, null, 4), 'utf8');
} catch (err) {
    node.error("Erreur JSON: " + err);
}

// --- SORTIE REFRESH ---
return {
    topic: "refresh",
    payload: true
};
